-    if (!placeholder.is_empty()) {
-      os::PlaceholderRegionPair split = os::split_memory(placeholder, ccs_begin_offset);
-
-      char* archive_base = os::convert_to_reserved(split.left);
-      char* class_base   = os::convert_to_reserved(split.right);
